+++ b/staging/src/k8s.io/apimachinery/pkg/runtime/serializer/cbor/internal/modes/custom.go
@@ -114,7 +114,15 @@ type checkers struct {

 func (cache *checkers) getChecker(rt reflect.Type) checker {
 	if ptr, ok := cache.m.Load(rt); ok {
-		return *ptr.(*checker)
+		// The pointer in the map always points to a checker that was stored by
+		// getCheckerInternal. That checker may still be a placeholder (not yet
+		// updated with the final safe/check functions). Avoid a data race by
+		// calling through the pointer rather than copying the struct value.
+		p := ptr.(*checker)
+		return checker{
+			safe:  func() bool { return p.safe() },
+			check: func(rv reflect.Value, depth int) error { return p.check(rv, depth) },
+		}
 	}

 	return cache.getCheckerInternal(rt, nil)

